package com.company.supervision.application.scheduling;
import com.company.supervision.domain.model.TaskSchedule;import com.company.supervision.entity.dto.schedule.ScheduleRule;import com.company.supervision.infrastructure.repository.ScheduleMapper;import com.company.supervision.infrastructure.scheduler.SupervisionJob;import com.fasterxml.jackson.databind.ObjectMapper;import org.quartz.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.time.*;import java.time.format.DateTimeFormatter;import java.util.*;
@Service public class AdvancedScheduleService{private final Scheduler scheduler;private final ScheduleMapper mapper;private final ObjectMapper json;private final NationalWorkdayCalendar calendar;public AdvancedScheduleService(Scheduler s,ScheduleMapper m,ObjectMapper j,NationalWorkdayCalendar c){scheduler=s;mapper=m;json=j;calendar=c;}
 public List<LocalDateTime>preview(ScheduleRule r){validate(r);ZoneId zone=ZoneId.of(r.getTimezone());List<LocalDateTime>out=new ArrayList<>();if("WORKDAY".equals(r.getMode()))return calendar.next(r.getTimes(),zone,5,r.getEndAt());if("ONCE".equals(r.getMode())){out.add(r.getStartAt());return out;}Date cursor=new Date();for(String cron:compile(r)){try{CronExpression e=new CronExpression(cron);e.setTimeZone(TimeZone.getTimeZone(zone));for(int i=0;i<5&&out.size()<5;i++){cursor=e.getNextValidTimeAfter(cursor);if(cursor==null)break;LocalDateTime n=LocalDateTime.ofInstant(cursor.toInstant(),zone);if(r.getEndAt()==null||!n.isAfter(r.getEndAt()))out.add(n);}}catch(Exception x){throw new IllegalArgumentException("Invalid schedule: "+x.getMessage());}}return out.stream().sorted().limit(5).toList();}
 public List<String>compile(ScheduleRule r){validate(r);if("CRON".equals(r.getMode()))return List.of(r.getCronExpression());List<String>times=r.getTimes()==null||r.getTimes().isEmpty()?List.of("09:00"):r.getTimes();List<String>out=new ArrayList<>();for(String t:times){LocalTime x=LocalTime.parse(t,DateTimeFormatter.ofPattern("HH:mm"));String pre=x.getSecond()+" "+x.getMinute()+" "+x.getHour()+" ";switch(r.getMode()){case"DAILY","WORKDAY"->out.add(pre+"* * ?");case"WEEKLY"->out.add(pre+"? * "+r.getDaysOfWeek().stream().map(this::dow).reduce((a,b)->a+","+b).orElseThrow());case"MONTHLY"->out.add(pre+String.join(",",r.getDaysOfMonth().stream().map(String::valueOf).toList())+" * ?");case"INTERVAL"->{if("MINUTE".equals(r.getIntervalUnit()))out.add("0 0/"+r.getInterval()+" * * * ?");else out.add("0 0 0/"+r.getInterval()+" * * ?");}default->throw new IllegalArgumentException("Unsupported recurring mode: "+r.getMode());}}return out;}
 @Transactional public void save(Long taskId,ScheduleRule r,String legacyCron){if(r==null&&legacyCron!=null&&!legacyCron.isBlank()){r=new ScheduleRule();r.setMode("CRON");r.setCronExpression(legacyCron);}TaskSchedule old=mapper.selectByTaskId(taskId);if(r==null||"MANUAL".equals(r.getMode())){if(old!=null)mapper.deleteById(old.getId());remove(taskId);return;}List<LocalDateTime>next=preview(r);TaskSchedule s=old==null?new TaskSchedule():old;s.setTaskId(taskId);s.setScheduleMode(r.getMode());s.setRuleVersion(r.getRuleVersion());try{s.setRuleJson(json.writeValueAsString(r));s.setRetryPolicyJson(json.writeValueAsString(Map.of("timeoutSeconds",r.getTimeoutSeconds(),"maxRetries",r.getMaxRetries(),"delaySeconds",r.getRetryDelaySeconds(),"backoff",r.getRetryBackoff())));}catch(Exception e){throw new IllegalArgumentException(e);}s.setCronExpression("CRON".equals(r.getMode())?r.getCronExpression():String.join(";",compile(r)));s.setTimezone(r.getTimezone());s.setStartAt(r.getStartAt());s.setEndAt(r.getEndAt());s.setMisfirePolicy(r.getMisfirePolicy());s.setOverlapPolicy(r.getOverlapPolicy());s.setHolidayPolicy(r.getHolidayPolicy());s.setNextFireTime(next.isEmpty()?null:next.get(0));s.setStatus(1);if(s.getId()==null)mapper.insert(s);else mapper.updateById(s);register(taskId,r);}
 public void restore(TaskSchedule s){try{ScheduleRule r=s.getRuleJson()==null?null:json.readValue(s.getRuleJson(),ScheduleRule.class);if(r!=null)register(s.getTaskId(),r);}catch(Exception e){throw new IllegalStateException("Restore schedule failed",e);}}
 public void register(Long taskId,ScheduleRule r){try{remove(taskId);JobDetail job=JobBuilder.newJob(SupervisionJob.class).withIdentity("task-"+taskId).storeDurably().usingJobData("taskId",taskId).build();scheduler.addJob(job,false);if("ONCE".equals(r.getMode())){Trigger tr=TriggerBuilder.newTrigger().withIdentity("trig-"+taskId+"-0").forJob(job).startAt(Date.from(r.getStartAt().atZone(ZoneId.of(r.getTimezone())).toInstant())).build();scheduler.scheduleJob(tr);return;}int i=0;for(String cron:compile(r)){CronScheduleBuilder b=CronScheduleBuilder.cronSchedule(cron).inTimeZone(TimeZone.getTimeZone(r.getTimezone()));if("DO_NOTHING".equals(r.getMisfirePolicy()))b=b.withMisfireHandlingInstructionDoNothing();else b=b.withMisfireHandlingInstructionFireAndProceed();TriggerBuilder<CronTrigger>tb=TriggerBuilder.newTrigger().withIdentity("trig-"+taskId+"-"+i++).forJob(job).withSchedule(b);if(r.getStartAt()!=null)tb.startAt(Date.from(r.getStartAt().atZone(ZoneId.of(r.getTimezone())).toInstant()));if(r.getEndAt()!=null)tb.endAt(Date.from(r.getEndAt().atZone(ZoneId.of(r.getTimezone())).toInstant()));scheduler.scheduleJob(tb.build());}}catch(Exception e){throw new IllegalStateException("Register schedule failed: "+e.getMessage(),e);}}
 public void remove(Long taskId){try{scheduler.deleteJob(JobKey.jobKey("task-"+taskId));}catch(Exception e){throw new IllegalStateException(e);}}private void validate(ScheduleRule r){if(r==null||r.getMode()==null)throw new IllegalArgumentException("Schedule mode required");ZoneId.of(r.getTimezone());if(r.getStartAt()!=null&&r.getEndAt()!=null&&r.getEndAt().isBefore(r.getStartAt()))throw new IllegalArgumentException("End must be after start");if("ONCE".equals(r.getMode())&&r.getStartAt()==null)throw new IllegalArgumentException("One-time schedule requires startAt");if("CRON".equals(r.getMode())&&!CronExpression.isValidExpression(r.getCronExpression()))throw new IllegalArgumentException("Invalid Cron expression");if("WEEKLY".equals(r.getMode())&&(r.getDaysOfWeek()==null||r.getDaysOfWeek().isEmpty()))throw new IllegalArgumentException("Select weekdays");if("MONTHLY".equals(r.getMode())&&(r.getDaysOfMonth()==null||r.getDaysOfMonth().isEmpty()))throw new IllegalArgumentException("Select month days");}private String dow(int d){return switch(d){case 1->"MON";case 2->"TUE";case 3->"WED";case 4->"THU";case 5->"FRI";case 6->"SAT";case 7->"SUN";default->throw new IllegalArgumentException("Invalid weekday");};}}